module thermal_sensor_calibration (
    input [4:0] sensor_reading,
    output [4:0] calibrated_value
);
      wire _n01 = sensor_reading[0] ^ 5[0];
  wire _c01 = sensor_reading[0] & 5[0];
  wire _n02 = sensor_reading[1] ^ 5[1] ^ _c01;
  wire _c02 = (sensor_reading[1] & 5[1]) | (sensor_reading[1] & _c01) | (5[1] & _c01);
  wire _n03 = sensor_reading[2] ^ 5[2] ^ _c02;
  wire _c03 = (sensor_reading[2] & 5[2]) | (sensor_reading[2] & _c02) | (5[2] & _c02);
  wire _n04 = sensor_reading[3] ^ 5[3] ^ _c03;
  wire _c04 = (sensor_reading[3] & 5[3]) | (sensor_reading[3] & _c03) | (5[3] & _c03);
  assign calibrated_value = {_n01, _n02, _n03, _n04};
endmodule
